+    fn reload_memdb_rows_from_txn_preserving_schema(
+        &self,
+        cx: &Cx,
+        txn: &mut dyn TransactionHandle,
+        bound_visible_commit_seq: CommitSeq,
+    ) -> Result<()> {
+        let _record_profile_scope = enter_record_profile_scope(RecordProfileScope::CoreConnection);
+        let page1 = txn.get_page(cx, PageNumber::ONE)?;
+        let header = parse_database_header_checked(page1.as_ref())?;
+        let page_size = header.page_size;
+        let reserved_per_page = header.reserved_per_page;
+
+        let schema = self.schema.borrow().clone();
+        let rowid_alias_columns = self.rowid_alias_columns.borrow().clone();
+        let mut new_db = self.db.borrow().clone();
+        let mut new_sqlite_sequence_cache = HashMap::new();
+
+        for table in &schema {
+            if table.root_page <= 0 {
+                continue;
+            }
+            if let Some(mem_table) = new_db.get_table_mut(table.root_page) {
+                mem_table.clear();
+            } else {
+                new_db.create_table_at(table.root_page, table.columns.len());
+            }
+            for index in &table.indexes {
+                if let Some(index_table) = new_db.get_table_mut(index.root_page) {
+                    index_table.clear();
+                } else {
+                    new_db.create_table_at(index.root_page, 0);
+                }
+            }
+        }
+
+        for table in &schema {
+            if table.root_page <= 0 {
+                continue;
+            }
+            let root_page = PageNumber::new(u32::try_from(table.root_page).unwrap_or(1))
+                .unwrap_or(PageNumber::ONE);
+            let mut cursor =
+                Self::new_header_btree_cursor(txn, root_page, page_size, reserved_per_page, true);
+            let num_columns = table.columns.len();
+            let ipk_col_idx = rowid_alias_columns
+                .get(&table.name.to_ascii_lowercase())
+                .copied();
+
+            if cursor.first(cx)? {
+                if table.without_rowid {
+                    return Err(FrankenError::NotImplemented(format!(
+                        "reloading populated WITHOUT ROWID table `{}` into MemDatabase is not yet supported",
+                        table.name
+                    )));
+                }
+                loop {
+                    let rowid = cursor.rowid(cx)?;
+                    let payload = cursor.payload(cx)?;
+                    let mut values =
+                        parse_record(&payload).ok_or_else(|| FrankenError::DatabaseCorrupt {
+                            detail: format!(
+                                "table `{}` rowid {rowid} payload is not a valid SQLite record",
+                                table.name
+                            ),
+                        })?;
+                    if table.name.eq_ignore_ascii_case("sqlite_sequence")
+                        && values.len() >= 2
+                        && let (SqliteValue::Text(tbl_name), SqliteValue::Integer(seq)) =
+                            (&values[0], &values[1])
+                    {
+                        new_sqlite_sequence_cache.insert(tbl_name.to_ascii_lowercase(), *seq);
+                    }
+                    if let Some(ipk_idx) = ipk_col_idx {
+                        match values.len() {
+                            len if len + 1 == num_columns => {
+                                values.insert(ipk_idx, SqliteValue::Integer(rowid));
+                            }
+                            len if len == num_columns => match values.get_mut(ipk_idx) {
+                                Some(slot @ SqliteValue::Null) => {
+                                    *slot = SqliteValue::Integer(rowid);
+                                }
+                                Some(SqliteValue::Integer(encoded_rowid))
+                                    if *encoded_rowid == rowid => {}
+                                Some(SqliteValue::Integer(encoded_rowid)) => {
+                                    return Err(FrankenError::DatabaseCorrupt {
+                                        detail: format!(
+                                            "table `{}` rowid {rowid} stores inconsistent INTEGER PRIMARY KEY alias value {encoded_rowid}",
+                                            table.name
+                                        ),
+                                    });
+                                }
+                                Some(other) => {
+                                    return Err(FrankenError::DatabaseCorrupt {
+                                        detail: format!(
+                                            "table `{}` rowid {rowid} stores non-integer INTEGER PRIMARY KEY alias value {other:?}",
+                                            table.name
+                                        ),
+                                    });
+                                }
+                                None => {
+                                    return Err(FrankenError::DatabaseCorrupt {
+                                        detail: format!(
+                                            "table `{}` rowid {rowid} payload is missing INTEGER PRIMARY KEY alias column",
+                                            table.name
+                                        ),
+                                    });
+                                }
+                            },
+                            len => {
+                                return Err(FrankenError::DatabaseCorrupt {
+                                    detail: format!(
+                                        "table `{}` rowid {rowid} payload has {len} columns; expected {} or {}",
+                                        table.name,
+                                        num_columns.saturating_sub(1),
+                                        num_columns
+                                    ),
+                                });
+                            }
+                        }
+                    }
+                    if let Some(mem_table) = new_db.get_table_mut(table.root_page) {
+                        mem_table.insert_row(rowid, values);
+                    }
+                    if !cursor.next(cx)? {
+                        break;
+                    }
+                }
+            }
+        }
+
+        *self.db.borrow_mut() = new_db;
+        *self.sqlite_sequence_cache.borrow_mut() = new_sqlite_sequence_cache;
